#define IMEM_IMAGE_WORDS ((u32)(sizeof(imem_image) / sizeof(imem_image[0])))
#define DMEM_IMAGE_WORDS ((u32)(sizeof(dmem_image) / sizeof(dmem_image[0])))

static void load_bram(UINTPTR base, const u32 *data, u32 word_count, u32 range_bytes) {
    u32 max_words = range_bytes / 4U;
    if (word_count > max_words) {
        word_count = max_words;
    }
    const u32 progress_step = 256U;
    for (u32 i = 0; i < word_count; ++i) {
        if (i == 0U) {
            xil_printf("[Host] load_bram: about to write first word to base=0x%08x\n\r", (unsigned)(base));
        }
        Xil_Out32(base + (i * 4U), data[i]);
        if (i == 0U) {
            xil_printf("[Host] load_bram: first word written to base=0x%08x\n\r", (unsigned)(base));
        }
        if ((i % progress_step) == 0U) {
            xil_printf("[Host] load_bram: base=0x%08x written %lu/%lu\n\r", (unsigned)(base), (unsigned long)(i), (unsigned long)word_count);
        }
    }
    xil_printf("[Host] load_bram: base=0x%08x DONE (%lu words)\n\r", (unsigned)(base), (unsigned long)word_count);
}

static void gpio_reset_init(void) {
    // axi_gpio_0 is already configured as a 1-bit output in the BD.
    xil_printf("[Host] gpio_reset_init: TRI init skipped; BD already sets output mode\n\r");
}

static void gpio_reset_write(u32 value) {
    xil_printf("[Host] gpio_reset_write: value=0x%08x\n\r", value);
    Xil_Out32(GPIO_BASE + GPIO_DATA_OFFSET, value);
}

static void reset_pulse(void) {
    gpio_reset_write(RESET_ASSERT_VALUE);
    usleep(10);
    gpio_reset_write(RESET_DEASSERT_VALUE);
}

static void dump_dmem_words(UINTPTR base, u32 start_word, u32 count) {
    for (u32 i = 0; i < count; ++i) {
        u32 value = Xil_In32(base + ((start_word + i) * 4U));
        xil_printf("[DMEM] 0x%08x = 0x%08x\n\r", (unsigned)(base + ((start_word + i) * 4U)), value);
    }
}

static u32 read_status_word(UINTPTR base, u32 offset) {
    Xil_DCacheInvalidateRange(base + offset, 64U);
    return Xil_In32(base + offset);
}

int main(void) {
    init_platform();
    xil_printf("[Host] Zynq BRAM loader start\n\r");

    xil_printf("[Host] Step 0: init_platform done\n\r");

    if (STATUS_OFFSET + 8U > DMEM_RANGE_BYTES) {
        xil_printf("[Host] Warning: STATUS_OFFSET exceeds DMEM_RANGE_BYTES. Update ranges or offsets.\n\r");
    }

    xil_printf("[Host] Step 1: gpio_reset_init()\n\r");
    gpio_reset_init();
    xil_printf("[Host] Step 1 done\n\r");

    xil_printf("[Host] Step 2: assert reset\n\r");
    gpio_reset_write(RESET_ASSERT_VALUE);
    xil_printf("[Host] Step 2 done\n\r");

    xil_printf("[Host] Step 3: load IMEM begin\n\r");
    xil_printf("[Host] Loading IMEM (%lu words)\n\r", (unsigned long)IMEM_IMAGE_WORDS);
    load_bram(IMEM_BRAM_BASE, imem_image, IMEM_IMAGE_WORDS, IMEM_RANGE_BYTES);
    xil_printf("[Host] Step 3 done\n\r");

    xil_printf("[Host] Step 4: load DMEM begin\n\r");
    xil_printf("[Host] Loading DMEM (%lu words)\n\r", (unsigned long)DMEM_IMAGE_WORDS);
    load_bram(DMEM_BRAM_BASE, dmem_image, DMEM_IMAGE_WORDS, DMEM_RANGE_BYTES);
    xil_printf("[Host] Step 4 done\n\r");

    // Ensure PS writes reach BRAM before releasing reset
    xil_printf("[Host] Step 5: cache flush begin\n\r");
    Xil_DCacheFlushRange(IMEM_BRAM_BASE, IMEM_RANGE_BYTES);
    Xil_DCacheFlushRange(DMEM_BRAM_BASE, DMEM_RANGE_BYTES);
    xil_printf("[Host] Step 5 done\n\r");

    /* Dump first words of IMEM to verify host wrote the image */
    xil_printf("[Host] IMEM dump before reset:\n\r");
    dump_dmem_words(IMEM_BRAM_BASE, 0U, 8U);

    xil_printf("[Host] DMEM status block before reset:\n\r");
    dump_dmem_words(DMEM_BRAM_BASE, STATUS_OFFSET / 4U, 4U);

    xil_printf("[Host] Step 6: release reset begin\n\r");
    xil_printf("[Host] Releasing reset\n\r");
    reset_pulse();
    xil_printf("[Host] Step 6 done\n\r");

    /* Early status read immediately after releasing reset */
    u32 early_status = read_status_word(DMEM_BRAM_BASE, STATUS_OFFSET);
#if ENABLE_ALT_STATUS_CHECK
    u32 early_status_alt = read_status_word(DMEM_BRAM_BASE, STATUS_ALT_OFFSET);
#else
    u32 early_status_alt = 0U;
#endif
    xil_printf("[Host] Early status read: offset 0x%08x -> 0x%08x\n\r", STATUS_OFFSET, early_status);
#if ENABLE_ALT_STATUS_CHECK
    xil_printf("[Host] Early status read: offset 0x%08x -> 0x%08x\n\r", STATUS_ALT_OFFSET, early_status_alt);
#endif
    xil_printf("[Host] DMEM dump after reset:\n\r");
    dump_dmem_words(DMEM_BRAM_BASE, 0U, 4U);

    xil_printf("[Host] Step 7: poll status begin\n\r");
#if ENABLE_ALT_STATUS_CHECK
    xil_printf("[Host] Polling status (offset 0x0 + 0x8000)...\n\r");
#else
    xil_printf("[Host] Polling status (offset 0x0 only)...\n\r");
#endif
    u32 status = 0U;
    u32 status_alt = 0U;
    u32 hit_offset = STATUS_OFFSET;
    const u32 max_poll = 200000000U;
    for (u32 i = 0; i < max_poll; ++i) {
        status = read_status_word(DMEM_BRAM_BASE, STATUS_OFFSET);
#if ENABLE_ALT_STATUS_CHECK
        status_alt = read_status_word(DMEM_BRAM_BASE, STATUS_ALT_OFFSET);
#else
        status_alt = 0U;
#endif

        if (status == STATUS_DONE_VALUE) {
            hit_offset = STATUS_OFFSET;
            break;
        }
#if ENABLE_ALT_STATUS_CHECK
        if (status_alt == STATUS_DONE_VALUE) {
            hit_offset = STATUS_ALT_OFFSET;
            status = status_alt;
            break;
        }
#endif
        if (status == STATUS_FAIL_VALUE || (ENABLE_ALT_STATUS_CHECK && status_alt == STATUS_FAIL_VALUE)) {
            hit_offset = (status == STATUS_FAIL_VALUE) ? STATUS_OFFSET : STATUS_ALT_OFFSET;
            status = STATUS_FAIL_VALUE;
            break;
        }

        if ((i % 100000U) == 0U) {
            usleep(1000);
        }
        if ((i % 20000000U) == 0U) {
    #if ENABLE_ALT_STATUS_CHECK
            xil_printf("[Host] poll=%lu status@0x0=0x%08x status@0x8000=0x%08x\n\r",
                   (unsigned long)i, status, status_alt);
    #else
            xil_printf("[Host] poll=%lu status@0x0=0x%08x\n\r",
                   (unsigned long)i, status);
    #endif
        }
    }

    if (status == STATUS_DONE_VALUE) {
        u32 label = Xil_In32(DMEM_BRAM_BASE + hit_offset + 0x4U);
        xil_printf("[Host] DONE: offset=0x%08x status=0x%08x, predicted=%lu\n\r",
                   hit_offset, status, (unsigned long)label);
    } else if (status == STATUS_FAIL_VALUE) {
        xil_printf("[Host] FAIL: offset=0x%08x status=0x%08x\n\r", hit_offset, status);
        dump_dmem_words(DMEM_BRAM_BASE, 0U, 16U);
        } else {
    #if ENABLE_ALT_STATUS_CHECK
        xil_printf("[Host] TIMEOUT: status@0x0=0x%08x status@0x8000=0x%08x\n\r", status, status_alt);
    #else
        xil_printf("[Host] TIMEOUT: status@0x0=0x%08x\n\r", status);
    #endif
        dump_dmem_words(DMEM_BRAM_BASE, 0U, 16U);
    #if ENABLE_ALT_STATUS_CHECK
        dump_dmem_words(DMEM_BRAM_BASE, STATUS_ALT_OFFSET / 4U, 8U);
    #endif
    }

    cleanup_platform();
    return 0;
}
